#include <stdio.h>
#include <stdlib.h>

int main() {
    int T; scanf("%d", &T);
    while (T--) {
        int N; scanf("%d", &N);
        int *brackets = (int*)malloc(N * sizeof(int));
        for (int i = 0; i < N; ++i) scanf("%d", &brackets[i]);
        int *stack = (int*)malloc(N * sizeof(int));
        int top = -1;
        int maxDepth = 0, maxDepthPos = 0, maxLength = 0, maxLengthPos = 0;
        for (int i = 0; i < N; ++i) {
            if (brackets[i] == 1) { // opening
                stack[++top] = i;
                if (top + 1 > maxDepth) {
                    maxDepth = top + 1;
                    maxDepthPos = i + 1; // 1‑based
                }
            } else { // closing
                int start = stack[top--];
                int length = i - start + 1;
                if (length > maxLength) {
                    maxLength = length;
                    maxLengthPos = start + 1; // 1‑based
                }
            }
        }
        printf("%d %d %d %d\n", maxDepth, maxDepthPos, maxLength, maxLengthPos);
        free(brackets);
        free(stack);
    }
    return 0;
}

