      stack.push(i);
      if (stack.length > maxDepth) {
        maxDepth = stack.length;
        maxDepthPos = i + 1; // 1‑based
      }
    } else { // closing
      const start = stack.pop();
      const length = i - start + 1;
      if (length > maxLength) {
        maxLength = length;
        maxLengthPos = start + 1; // 1‑based
      }
    }
